def parse_duration(s: str) -> int:
    """
    Преобразует строку вида '2h30m', '45m', '1h', '90s' в количество секунд.

    Args:
        s (str): Строка вида '2h30m', '45m', '1h', '90s'

    Returns:
        int: Количество секунд

    Raises:
        ValueError: Если входная строка невалидна
    """
    seconds = 0
    num = ''
    for char in s:
        if char.isdigit():
            num += char
        else:
            if num == '':
                raise ValueError("Невалидный ввод")
            if char == 'h':
                seconds += int(num) * 3600
            elif char == 'm':
                seconds += int(num) * 60
            elif char == 's':
                seconds += int(num)
            else:
                raise ValueError("Невалидный ввод")
            num = ''
    if num != '':
        raise ValueError("Невалидный ввод")
    return seconds
